import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly encoding user input to prevent XSS
        String encodedUserInput = encodeForHtml(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + encodedUserInput + "</h1>"); // User input is now properly encoded
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        // Replace special characters with their HTML entity equivalents to prevent XSS
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
